.darma-loader-loaders-css-17 {
  display: inline-block;
  width: 45px;
  height: 45px;
  border-radius: 12px;
  background: linear-gradient(135deg, var(--loader-color, #06b6d4), var(--loader-secondary-color, #bae6fd));
  animation: darma-loader-loaders-css-17-squareFlip 1.0s cubic-bezier(.55,.08,.38,.97) infinite;
}
@keyframes darma-loader-loaders-css-17-squareFlip { 0% { transform: perspective(120px) rotateX(0) rotateY(0); } 50% { transform: perspective(120px) rotateX(-180deg) rotateY(0); } 100% { transform: perspective(120px) rotateX(-180deg) rotateY(-180deg); } }

